  <title>Collaborative Maze Exploration Game</title>
  <style>
    body {
      margin: 0;
      padding: 20px;
      background-color: #1e1e24;
      color: #f5f5f7;
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      display: flex;
      flex-direction: column;
